<?php
/* Plugin Name: HongChong Theme Installer */
register_activation_hook(__FILE__, function() {
  $dir = WP_CONTENT_DIR . "/themes/hongchong-theme";
  if (!is_dir($dir)) mkdir($dir, 0755, true);
  if (!is_dir($dir."/inc")) mkdir($dir."/inc", 0755, true);
  file_put_contents("$dir/functions.php", base64_decode(""));
  file_put_contents("$dir/style.css", base64_decode(""));
  file_put_contents("$dir/inc/cpt-inquiry.php", base64_decode(""));
  file_put_contents("$dir/inc/cpt-misc.php", base64_decode(""));
  file_put_contents("$dir/inc/cpt-products.php", base64_decode(""));
  file_put_contents("$dir/inc/email.php", base64_decode(""));
  file_put_contents("$dir/inc/rest-api.php", base64_decode(""));
  file_put_contents("$dir/inc/seo-helpers.php", base64_decode(""));
  switch_theme("hongchong-theme");
  if (!term_exists("glass-bottles", "product_category")) {
    wp_insert_term("Glass Bottles", "product_category", ["slug"=>"glass-bottles"]);
    wp_insert_term("Glass Jars", "product_category", ["slug"=>"glass-jars"]);
    wp_insert_term("Glass Vases", "product_category", ["slug"=>"glass-vases"]);
  }
  deactivate_plugins(plugin_basename(__FILE__));
});